mapper.select:
SELECT a.*, u.username, u.nickname, u.avatar as avatar, c.name as categoryName FROM blog_article a LEFT JOIN sys_user u ON a.author_id = u.id LEFT JOIN blog_category c ON a.category_id = c.id WHERE a.author_id = #{userId} AND a.deleted = false
AND a.status = #{status}
ORDER BY a.create_time DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*)
FROM blog_article
WHERE user_id = #{userId}

    AND status = #{status}


    AND (title LIKE CONCAT('%', #{keyword}, '%')
         OR content LIKE CONCAT('%', #{keyword}, '%')
         OR summary LIKE CONCAT('%', #{keyword}, '%'))


    AND a.mood = #{mood}

  AND deleted = false
